(()=>{const $=(s,r=document)=>r.querySelector(s);const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));const panel=()=>$('#panel');const sidebar=()=>$('[data-sidebar]');const loadbar=()=>$('#loadbar');function syncActive(){const cur=location.pathname.replace(/\/+$/,'')|| '/';$$('[data-sidebar] a[data-link]').forEach(a=>{const path=new URL(a.href,location.origin).pathname.replace(/\/+$/,'')|| '/';a.classList.toggle('active',path===cur);});}const SKELETON='<div class="usgc-skeleton" aria-hidden="true"><div class="sk sk-h"></div><div class="sk sk-line"></div><div class="sk sk-line"></div><div class="sk sk-line w-2/3"></div></div>';function showSkeleton(){const p=panel();if(p)p.innerHTML=SKELETON;}let currentAbort=null;async function swap(url,push){const u=new URL(url,location.origin);if(u.origin !==location.origin){location.href=url;return;}if(currentAbort)currentAbort.abort();const abort=new AbortController();currentAbort=abort;const sep=u.search ? '&':'?';loadbar()?.classList.add('loading');const skTimer=setTimeout(()=>{if(!abort.signal.aborted)showSkeleton();},120);try{const r=await fetch(u.pathname + u.search + sep + 'partial=1',{headers:{'X-Partial':'1'},credentials:'same-origin',signal:abort.signal,});if(!r.ok)throw 0;const html=await r.text();if(abort.signal.aborted)return;clearTimeout(skTimer);const p=panel();if(!p){location.href=url;return;}p.innerHTML=html;if(push)history.pushState({swap:1},'',u.pathname + u.search);const t=p.querySelector('[data-title]');if(t)document.title=t.dataset.title || t.textContent.trim();const dd=p.querySelector('[data-description]');const metaDesc=document.querySelector('meta[name="description"]');if(dd && metaDesc)metaDesc.setAttribute('content',dd.dataset.description || '');syncActive();p.scrollIntoView({block:'start'});sidebar()?.classList.remove('translate-x-0');const h=p.querySelector('h1');if(h){if(!h.hasAttribute('tabindex'))h.setAttribute('tabindex','-1');try{h.focus({preventScroll:true});}catch(_){}}}catch(e){if(abort.signal.aborted)return;clearTimeout(skTimer);location.href=url;}finally{if(currentAbort===abort){currentAbort=null;loadbar()?.classList.remove('loading');}}}function renderPlayer(host,data){if(!host)return;if(!data || !data.src){host.innerHTML='<span class="usgc-sku" data-player-placeholder>NO SOURCE</span>';host.classList.add('vid-frame-empty');return;}host.classList.remove('vid-frame-empty');const autoplay=data.src.includes('?')? '&autoplay=1':'?autoplay=1';host.innerHTML='<iframe class="vid-frame" src="' + data.src + autoplay +
'" loading="lazy" allow="autoplay; encrypted-media; picture-in-picture; fullscreen" allowfullscreen' +
' referrerpolicy="strict-origin-when-cross-origin"></iframe>';}function pickVideo(btn){const section=btn.closest('.ar-video')|| document;const host=section.querySelector('#player')|| $('#player');$$('.vid-pick').forEach(b=>b.classList.toggle('active',b===btn));renderPlayer(host,{src:btn.dataset.vidSrc,title:btn.dataset.vidTitle || ''});}function setLibMode(mode){$$('[data-mode-set]').forEach(b=>b.classList.toggle('active',b.dataset.modeSet===mode));$$('.ar-library, .drawer-panel .ar-library').forEach(s=>s.dataset.mode=mode);$$('.lib-gui').forEach(el=>el.hidden=mode !=='gui');$$('.lib-list').forEach(el=>el.hidden=mode !=='list');}function escHtml(s){return String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));}function libResolve(root,path){let node=root;for(const seg of path){const child=(node.folders ||[]).find(f=>f.slug===seg);if(!child)return node;node=child;}return node;}function renderLibGrid(container){let tree;try{tree=JSON.parse(container.dataset.libTree || 'null');}catch(e){return;}if(!tree)return;const path=(container.dataset.libPath || '').split('/').filter(Boolean);const node=libResolve(tree,path);const grid=container.querySelector('[data-lib-grid]');const cwd=container.querySelector('[data-lib-cwd]');const up=container.querySelector('[data-lib-up]');if(cwd)cwd.textContent='/' + path.join('/');if(up)up.disabled=path.length===0;if(!grid)return;let html='';(node.folders ||[]).forEach(f=>{html +='<button type="button" class="lib-cell lib-cell-folder" data-lib-folder="' + escHtml(f.slug)+ '" title="' + escHtml(f.name)+ '">'
+ '<span class="lib-cell-icon" aria-hidden="true">[/]</span>'
+ '<span class="lib-cell-name">' + escHtml(f.name)+ '</span>'
+ '</button>';});(node.files ||[]).forEach(f=>{html +='<a class="lib-cell lib-cell-file" href="' + escHtml(f.url)+ '" download data-file title="' + escHtml(f.name)+ ' · ' + escHtml(f.size)+ '">'
+ '<span class="lib-cell-icon" aria-hidden="true">[ ]</span>'
+ '<span class="lib-cell-name">' + escHtml(f.name)+ '</span>'
+ '<span class="lib-cell-meta usgc-sku">' + escHtml(f.size)+ '</span>'
+ '</a>';});if(!html){html='<div class="usgc-sku lib-empty-grid">' + escHtml(container.dataset.libEmpty || 'empty')+ '</div>';}grid.innerHTML=html;}function renderAllLibGrids(){$$('.lib-gui[data-lib-tree]').forEach(renderLibGrid);}function libGo(container,segment){const cur=(container.dataset.libPath || '').split('/').filter(Boolean);segment ? cur.push(segment):cur.pop();container.dataset.libPath=cur.join('/');renderLibGrid(container);}let drawerCloned=false;function cloneIntoDrawer(){if(drawerCloned)return;const aside=$('[data-aside-right]');[['library','.ar-library'],['video','.ar-video']].forEach(([panel,sel])=>{const src=aside && aside.querySelector(sel);const dst=$(`[data-panel="${panel}"]`);if(src && dst)dst.appendChild(src.cloneNode(true));});drawerCloned=true;renderAllLibGrids();}function openDrawer(){const d=$('[data-drawer]');if(!d)return;cloneIntoDrawer();d.hidden=false;requestAnimationFrame(()=>d.classList.add('open'));}function closeDrawer(){const d=$('[data-drawer]');if(!d)return;d.classList.remove('open');setTimeout(()=>{d.hidden=true;},160);}function setDrawerTab(name){$$('[data-tab]').forEach(b=>{const on=b.dataset.tab===name;b.classList.toggle('active',on);b.setAttribute('aria-selected',on ? 'true':'false');});$$('[data-panel]').forEach(p=>p.hidden=p.dataset.panel !==name);}let ctxTargetUrl=null;function showCtx(x,y,url){ctxTargetUrl=url;const m=$('#ctxmenu');if(!m)return;m.style.left=x + 'px';m.style.top=y + 'px';m.style.right='auto';m.style.bottom='auto';m.hidden=false;}function hideCtx(){const m=$('#ctxmenu');if(m)m.hidden=true;ctxTargetUrl=null;}document.addEventListener('click',(e)=>{const lf=e.target.closest('[data-lib-folder]');if(lf){const container=lf.closest('.lib-gui[data-lib-tree]');if(container)libGo(container,lf.dataset.libFolder);return;}if(e.target.closest('[data-sidebar-toggle]')){sidebar()?.classList.toggle('translate-x-0');return;}if(e.target.closest('[data-theme-toggle]')){const dark=document.documentElement.classList.toggle('dark');try{localStorage.theme=dark ? 'dark':'light';}catch(_){}return;}const mode=e.target.closest('[data-mode-set]');if(mode){setLibMode(mode.dataset.modeSet);return;}const fold=e.target.closest('tr.lib-row-folder');if(fold){const id=fold.dataset.folder;const open=fold.classList.toggle('open');const root=fold.closest('table')|| document;const tog=fold.querySelector('.lib-toggle');if(tog)tog.textContent=open ? '[-]':'[+]';if(open){root.querySelectorAll('tr[data-parent="' + CSS.escape(id)+ '"]').forEach(r=>r.hidden=false);}else{root.querySelectorAll('tr[data-parent="' + CSS.escape(id)+ '"], tr[data-parent^="' + CSS.escape(id)+ '/"]').forEach(r=>{r.hidden=true;if(r.classList.contains('lib-row-folder')){r.classList.remove('open');const t=r.querySelector('.lib-toggle');if(t)t.textContent='[+]';}});}return;}const up=e.target.closest('[data-lib-up]');if(up){const container=up.closest('.lib-gui[data-lib-tree]');if(container)libGo(container);return;}const vid=e.target.closest('[data-video]');if(vid){pickVideo(vid);return;}if(e.target.closest('[data-drawer-toggle]')){const d=$('[data-drawer]');(d && !d.hidden)? closeDrawer():openDrawer();return;}if(e.target.closest('[data-drawer-close]')){closeDrawer();return;}const tab=e.target.closest('[data-tab]');if(tab){setDrawerTab(tab.dataset.tab);return;}const ctxBtn=e.target.closest('#ctxmenu button');if(ctxBtn && ctxTargetUrl){if(ctxBtn.dataset.ctx==='download'){const a=document.createElement('a');a.href=ctxTargetUrl;a.download='';document.body.appendChild(a);a.click();a.remove();}else if(ctxBtn.dataset.ctx==='copy'){try{navigator.clipboard?.writeText(ctxTargetUrl);}catch(_){}}hideCtx();return;}if(!e.target.closest('#ctxmenu'))hideCtx();const a=e.target.closest('a[data-link]');if(!a)return;if(e.metaKey || e.ctrlKey || e.shiftKey || e.button===1)return;e.preventDefault();swap(a.href,true);});document.addEventListener('contextmenu',(e)=>{const f=e.target.closest('a[data-file]');if(!f)return;e.preventDefault();showCtx(e.clientX,e.clientY,f.href);});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'){hideCtx();}});history.replaceState({swap:1},'',location.href);addEventListener('popstate',()=>{swap(location.href,false);});syncActive();renderAllLibGrids();})();
